import { dateToStr, dateToHours } from "../../utils/dates";
import { IconR, IconZ } from "../Simple/Image";
import "./Summary.css";

import { useState, useEffect, Form } from "../../cdn";
import type { ChangeEvent } from "../../cdn";

export const Summary = ({ data, setItemsSelectable, setActivePage1 }: any) => {
  const [isStcHidden, setIsStcHidden] = useState(false);
  const [isFlatHidden, setIsFlatHidden] = useState(false);
  const [isDistanceApplied, setIsDistanceApplied] = useState(false);
  const [distValue, setDistValue] = useState("0.3");

  // Set Selectable items
  useEffect(() => {
    const maxDistance = parseFloat(distValue);
    const itemsSelectable: any[] = [];
    data.items.forEach((item: any) => {
      if (
        (isStcHidden && item.sold_let) ||
        (isFlatHidden && item.property_group_icon === "🏢") ||
        (isDistanceApplied && item.closest && maxDistance && item.closest.miles > maxDistance)
      )
        return;
      itemsSelectable.push(item);
    });
    setItemsSelectable(itemsSelectable);
    console.log("itemsSelectable", itemsSelectable.length);

    // Go to 1st page as indexes changed
    setActivePage1(1);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isStcHidden, isFlatHidden, isDistanceApplied, setActivePage1, setItemsSelectable]);

  /**
   * Display STC
   */
  const numSTCs = data.items.filter((item: any) => item.sold_let).length;
  const numStcStr = `Exclude the ${numSTCs} STCs`;
  const OnStcCheckChanged = (event: InputEvent) => {
    setIsStcHidden((event.target as HTMLInputElement).checked);
  };

  /**
   * Display Flat
   */
  const numFlats = data.items.filter((item: any) => item.property_group_icon === "🏢").length;
  const numFlatsStr = `Exclude the ${numFlats} flats`;
  const OnFlatCheckChanged = (event: InputEvent) => {
    setIsFlatHidden((event.target as HTMLInputElement).checked);
  };

  /**
   * Display Distance
   */
  const onChangeDist = (value: string) => {
    setDistValue(value);
    setIsDistanceApplied(false);
  };
  const onKeyDown = (event: KeyboardEvent) => {
    if (event.key === "Enter") {
      event.preventDefault();
      setIsDistanceApplied(true);
    } else {
      setIsDistanceApplied(false);
    }
  };
  const OnDistanceCheckChanged = (event: ChangeEvent) => {
    setIsDistanceApplied((event.target as HTMLInputElement).checked);
  };

  return (
    <>
      <h1 style={{ textTransform: "uppercase" }}>{data.region}</h1>
      <h5>{data.title}</h5>
      <UpdatedOn data={data} />
      <AllSearches searches={data.searches} />
      <Form style={{ display: "flex", justifyContent: "center", flexWrap: "wrap" }}>
        <Form.Check
          type="switch"
          label={numStcStr}
          id="check-1"
          onChange={OnStcCheckChanged}
          checked={isStcHidden}
        />
      </Form>
      <Form style={{ display: "flex", justifyContent: "center", flexWrap: "wrap" }}>
        <Form.Check
          type="switch"
          label={numFlatsStr}
          id="check-2"
          onChange={OnFlatCheckChanged}
          checked={isFlatHidden}
        />
      </Form>
      <Form style={{ display: "flex", justifyContent: "center", flexWrap: "wrap" }}>
        <Form.Check
          type="switch"
          id="check-3"
          onChange={OnDistanceCheckChanged}
          checked={isDistanceApplied}
        />
        <p>Exclude further than</p>
        <Form.Control
          value={distValue}
          aria-label="Distance"
          aria-describedby="distance-entry"
          id="distance-miles"
          onChange={(e: ChangeEvent) => onChangeDist((e.target as HTMLInputElement).value)}
          style={{
            maxWidth: "3rem",
            height: "1.5rem",
            margin: "0 0.5rem",
            textAlign: "center",
          }}
          onKeyDown={onKeyDown}
        />
        <p>miles</p>
      </Form>
    </>
  );
};

const UpdatedOn = ({ data }: any) => {
  return (
    <p>
      Updated{" "}
      <span
        id="x-updated-relative"
        className="x-date-relative"
        data-convert="hours"
        data-date={data.updated_on}
      >
        {dateToHours(data.updated_on)}
      </span>{" "}
      ago
      <br />
      (on <span>{dateToStr(data.updated_on)}</span>
      )
      <br />
      next check starts in:{" "}
      <span
        id="x-nexton-relative"
        className="x-date-relative"
        data-convert="hours-negative"
        data-date={data.next_on}
      >
        {dateToHours(data.next_on, true)}
      </span>
    </p>
  );
};

const AllSearches = ({ searches }: any) => {
  return (
    <p>
      Results based on <IconR style={{ verticalAlign: "baseline" }} /> searches:
      <br />
      {searches &&
        searches
          .map((search: any, index: number) => <SearchItem key={index} search={search} />)
          .reduce((prev: any, curr: any) => [prev, " ◆ ", curr])}
    </p>
  );
};

const SearchItem = ({ search }: any) => {
  return (
    <span className="x-nowrap">
      <strong>{search.name}</strong>{" "}
      <a rel="noreferrer" target="_blank" href={search.url_r}>
        <IconR isLink={true} style={{ verticalAlign: "sub" }} />
      </a>{" "}
      <a rel="noreferrer" target="_blank" href={search.url_z}>
        <IconZ isLink={true} style={{ verticalAlign: "sub" }} />
      </a>
    </span>
  );
};

export default Summary;
