import { IconR, IconZ } from "../Simple/Image";
import { Elem } from "../Simple/Elem";

export const Links = ({ item }: any) => {
  const elems = [<Listing key="1" item={item} />];
  item.zoopla_advert_id && elems.push(<ZooplaListing key="2" item={item} />);
  !item.zoopla_advert_id && elems.push(<ZooplaSearchListing key="3" item={item} />);
  item.zoopla_uprn && elems.push(<ZooplaEstimate key="4" item={item} />);
  elems.push(<ZooplaEstimatesInStreet key="4" item={item} />);
  elems.push(<SoldInstreet key="5" item={item} />, <StreetEPCs key="6" item={item} />);
  item.epcs && elems.push(<EPCs key="7" item={item} />);
  const reduced = elems.reduce((prev: any, curr: any) => [prev, ", ", curr] as any);
  return (
    <p>
      <strong>Links:</strong> {reduced}
    </p>
  );
};

const Listing = ({ item }: any) => {
  const url = `https://www.rightmove.co.uk/properties/${item.id}#/?channel=${item.channel}`;
  return <Elem icon={<IconR />} url={url} text="Advert" />;
};

const SoldInstreet = ({ item }: any) => {
  const postcode: string = item.address_postcode.toLowerCase().replace(" ", "-");
  const url = `https://www.rightmove.co.uk/house-prices/${postcode}.html`;
  return <Elem icon={<IconR />} url={url} text="Sold in Street" />;
};

const ZooplaEstimate = ({ item }: any) => {
  const url = `https://www.zoopla.co.uk/property/uprn/${item.zoopla_uprn}/`;
  return <Elem icon={<IconZ />} url={url} text="Estimate" />;
};

const ZooplaEstimatesInStreet = ({ item }: any) => {
  const postcode: string = item.address_postcode.toLowerCase().replace(" ", "-");
  const url = `https://www.zoopla.co.uk/house-prices/${postcode}/?sortOrder=address&sortDirection=asc#:~:text=Properties%20for%20sale%20in`;
  return <Elem icon={<IconZ />} url={url} text="Estimates in Street" />;
};

const ZooplaListing = ({ item }: any) => {
  const url: string =
    item.channel === "rent"
      ? `https://www.zoopla.co.uk/to-rent/details/${item.zoopla_advert_id}/`
      : `https://www.zoopla.co.uk/for-sale/details/${item.zoopla_advert_id}/`;
  return <Elem icon={<IconZ />} url={url} text="Advert" />;
};

const ZooplaSearchListing = ({ item }: any) => {
  const postcode: string = item.address_postcode.toLowerCase().replace(" ", "-");
  const postcodePlus: string = item.address_postcode.replace(" ", "+");
  const url: string =
    item.channel === "rent"
      ? `https://www.zoopla.co.uk/to-rent/property/${postcode}/?radius=0&q=${postcodePlus}&search_source=to-rent&results_sort=newest_listings&include_rented=true`
      : `https://www.zoopla.co.uk/for-sale/property/${postcode}/?radius=0&q=${postcodePlus}&search_source=for-sale&results_sort=newest_listings&is_auction=false&is_retirement_home=false&is_shared_ownership=false&include_sold=true`;
  return <Elem icon={<IconZ />} url={url} text="Adverts in Street" />;
};

const StreetEPCs = ({ item }: any) => {
  const icon = <i className="fa-solid fa-leaf" style={{ color: "#659748" }}></i>;
  const postcodePlus: string = item.address_postcode.replace(" ", "+");
  const url = `https://find-energy-certificate.service.gov.uk/find-a-certificate/search-by-postcode?postcode=${postcodePlus}`;
  return <Elem icon={icon} url={url} text="EPCs in Street" />;
};

const EPCs = ({ item }: any) => {
  return (
    <>
      {<IconR />}{" "}
      {item.epcs
        .map((epc: any, index: number) => (
          <a key={index} rel="noreferrer" target="_blank" href={epc.url}>
            {epc.caption}
          </a>
        ))
        .reduce((prev: any, curr: any) => [prev, ", ", curr])}
    </>
  );
};

export default Links;
